"use client";

import { type KeyboardEvent, type RefObject, useCallback, useState } from "react";
import { dispatchNavigationKey, resolveDirectionKeys } from "../core/navigation-dispatch.js";
import { isEditableElement } from "../dom/element-guards.js";
import { containsActiveElement } from "../dom/focusable.js";
import {
  getFocusedNavigationValue,
  getNavigationItems,
  type NavigationItemType,
} from "../dom/navigation-items.js";

export type NavigationRole = NavigationItemType;

export interface UseNavigationOptions<TValue extends string = string> {
  containerRef: RefObject<HTMLElement | null>;
  role: NavigationRole;
  highlighted?: TValue | null;
  defaultHighlighted?: TValue | null;
  onHighlightChange?: (value: TValue | null) => void;
  onSelect?: (value: TValue, event: globalThis.KeyboardEvent) => void;
  onEnter?: (value: TValue, event: globalThis.KeyboardEvent) => void;
  wrap?: boolean;
  enabled?: boolean;
  preventDefault?: boolean;
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  upKeys?: readonly string[];
  downKeys?: readonly string[];
  orientation?: "vertical" | "horizontal";
  skipDisabled?: boolean;
  moveFocus?: boolean;
  scopeToContainer?: boolean;
  ownerSelector?: string | null;
}

export interface UseNavigationReturn<TValue extends string = string> {
  highlighted: TValue | null;
  isHighlighted: (value: TValue) => boolean;
  highlight: (value: TValue | null) => void;
  onKeyDown: (event: KeyboardEvent) => void;
}

interface UseNavigationCoreReturn<TValue extends string = string> {
  highlighted: TValue | null;
  isHighlighted: (value: TValue) => boolean;
  highlight: (value: TValue | null) => void;
  move: (delta: 1 | -1, event?: globalThis.KeyboardEvent, key?: string) => void;
  focusIndex: (index: number) => void;
  handleSelect: (event: globalThis.KeyboardEvent) => void;
  handleEnter: (event: globalThis.KeyboardEvent) => void;
  getElements: () => HTMLElement[];
}

function queryNavigationElements(
  containerRef: RefObject<HTMLElement | null>,
  role: NavigationRole,
  skipDisabled: boolean,
  scopeToContainer: boolean,
  ownerSelector: string | null | undefined,
): HTMLElement[] {
  return getNavigationItems(containerRef.current, {
    type: role,
    skipDisabled,
    scopeToContainer,
    ownerSelector,
  });
}

function wrapIndex(index: number, length: number, wrap: boolean): number | null {
  if (index < 0) return wrap ? length - 1 : null;
  if (index >= length) return wrap ? 0 : null;
  return index;
}

export function useNavigationCore<TValue extends string = string>({
  containerRef,
  role,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onEnter,
  onHighlightChange,
  wrap = true,
  onNavigationBoundaryReached,
  skipDisabled = true,
  moveFocus = false,
  scopeToContainer = true,
  ownerSelector,
}: UseNavigationOptions<TValue>): UseNavigationCoreReturn<TValue> {
  const [internalHighlighted, setInternalHighlighted] = useState<TValue | null>(defaultHighlighted);
  const isControlled = controlledHighlighted !== undefined;
  const highlighted = isControlled ? (controlledHighlighted ?? null) : internalHighlighted;

  const setFocusedValue = useCallback(
    (nextValue: TValue | null) => {
      if (!isControlled) setInternalHighlighted(nextValue);
      onHighlightChange?.(nextValue);
    },
    [isControlled, onHighlightChange],
  );

  const getElements = useCallback(
    () =>
      queryNavigationElements(containerRef, role, skipDisabled, scopeToContainer, ownerSelector),
    [containerRef, role, skipDisabled, scopeToContainer, ownerSelector],
  );

  const getFocusedIndex = useCallback((): number => {
    const elements = getElements();
    if (elements.length === 0) return -1;

    const focusedIndex = elements.findIndex(containsActiveElement);
    if (focusedIndex >= 0) return focusedIndex;

    if (highlighted !== null) {
      const index = elements.findIndex((el) => el.dataset.value === highlighted);
      if (index >= 0) return index;
    }

    return -1;
  }, [getElements, highlighted]);

  const getCurrentValue = useCallback((): TValue | null => {
    const focusedValue = getFocusedNavigationValue(containerRef.current, {
      type: role,
      skipDisabled,
      scopeToContainer,
      ownerSelector,
    });
    // DOM boundary: data-value is opaque to TS; consumers parameterize TValue.
    if (focusedValue !== null) return focusedValue as TValue;

    const elements = getElements();

    if (highlighted !== null) {
      return elements.some((el) => el.dataset.value === highlighted) ? highlighted : null;
    }

    return null;
  }, [containerRef, getElements, highlighted, ownerSelector, role, scopeToContainer, skipDisabled]);

  const focusIndex = useCallback(
    (index: number) => {
      const elements = getElements();
      const el = elements[index];
      if (!el) return;
      const nextValue = el.dataset.value;
      if (nextValue === undefined) return;

      el.scrollIntoView?.({ block: "nearest" });
      if (moveFocus) el.focus();
      // DOM boundary: data-value is opaque to TS; consumers parameterize TValue.
      setFocusedValue(nextValue as TValue);
    },
    [getElements, moveFocus, setFocusedValue],
  );

  const move = useCallback(
    (delta: 1 | -1, event?: globalThis.KeyboardEvent, key?: string) => {
      const elements = getElements();
      if (elements.length === 0) return;

      const current = getFocusedIndex();
      const rawNext = current + delta;
      const next = wrapIndex(rawNext, elements.length, wrap);
      if (next === null) {
        const direction = delta < 0 ? "previous" : "next";
        if (event && key) onNavigationBoundaryReached?.(direction, event, key);
        return;
      }

      focusIndex(next);
    },
    [focusIndex, getElements, getFocusedIndex, onNavigationBoundaryReached, wrap],
  );

  const handleSelect = useCallback(
    (event: globalThis.KeyboardEvent) => {
      const currentValue = getCurrentValue();
      if (currentValue !== null) onSelect?.(currentValue, event);
    },
    [getCurrentValue, onSelect],
  );

  const handleEnter = useCallback(
    (event: globalThis.KeyboardEvent) => {
      const currentValue = getCurrentValue();
      if (currentValue === null) return;
      if (onEnter) onEnter(currentValue, event);
      else onSelect?.(currentValue, event);
    },
    [getCurrentValue, onEnter, onSelect],
  );

  const isHighlighted = useCallback((v: TValue) => highlighted === v, [highlighted]);
  const highlight = useCallback((v: TValue | null) => setFocusedValue(v), [setFocusedValue]);

  return {
    highlighted,
    isHighlighted,
    highlight,
    move,
    focusIndex,
    handleSelect,
    handleEnter,
    getElements,
  };
}

export function useNavigation<TValue extends string = string>(
  options: UseNavigationOptions<TValue>,
): UseNavigationReturn<TValue> {
  const {
    enabled = true,
    preventDefault = true,
    orientation = "vertical",
    upKeys,
    downKeys,
    onEnter,
    onSelect,
  } = options;

  const { resolvedUpKeys, resolvedDownKeys } = resolveDirectionKeys(orientation, upKeys, downKeys);

  const {
    highlighted,
    isHighlighted,
    highlight,
    move,
    focusIndex,
    handleSelect,
    handleEnter,
    getElements,
  } = useNavigationCore(options);
  const handlesEnter = Boolean(onEnter || onSelect);
  const handlesSpace = Boolean(onSelect);

  const onKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (!enabled) return;

      const key = event.key;
      const isMoveKey = resolvedUpKeys.includes(key) || resolvedDownKeys.includes(key);
      const isSpecialKey =
        key === "Home" ||
        key === "End" ||
        (key === "Enter" && handlesEnter) ||
        (key === " " && handlesSpace);
      if (!isMoveKey && !isSpecialKey) return;

      const elements = getElements();

      // Editable target guard: when an editable element bubbles a key into a wrapper
      // that ALSO owns the navigation container, let the native control handle the key.
      // We only skip when:
      //   1) the event target is editable,
      //   2) the target is NOT itself a navigation item,
      //   3) currentTarget is an ancestor of the items (natural bubble case),
      //      so the user did not explicitly forward the event from the editable.
      if (isEditableElement(event.target)) {
        const target = event.target as HTMLElement;
        const isOwnItem = elements.some((el) => el === target || el.contains(target));
        const currentTarget = event.currentTarget;
        const ownsItems =
          currentTarget != null &&
          elements.length > 0 &&
          elements.every((el) => currentTarget.contains(el));
        if (!isOwnItem && ownsItems) return;
      }

      if (preventDefault) event.preventDefault();

      dispatchNavigationKey(key, {
        resolvedUpKeys,
        resolvedDownKeys,
        move: (delta) => move(delta, event.nativeEvent, key),
        focusIndex,
        handleSelect: handlesSpace ? (e) => handleSelect(e) : undefined,
        handleEnter: handlesEnter ? (e) => handleEnter(e) : undefined,
        total: elements.length,
        nativeEvent: event.nativeEvent,
      });
    },
    [
      enabled,
      resolvedUpKeys,
      resolvedDownKeys,
      preventDefault,
      handlesEnter,
      handlesSpace,
      move,
      focusIndex,
      handleSelect,
      handleEnter,
      getElements,
    ],
  );

  return { highlighted, isHighlighted, highlight, onKeyDown };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import {
  getRestorableFocusTarget,
  type RestoreFocusOptions,
  restoreFocus,
} from "../dom/focus-restore.js";

export interface UseFocusRestoreOptions extends RestoreFocusOptions {
  enabled?: boolean;
  restoreOnUnmount?: boolean;
  fallback?: HTMLElement | null;
}

export interface UseFocusRestoreReturn {
  capture: (ownerDocument?: Document) => HTMLElement | null;
  restore: () => boolean;
  target: HTMLElement | null;
}

interface FocusRestoreEntry {
  target: HTMLElement | null;
  ownerDocument: Document;
}

const focusRestoreStacks = new WeakMap<Document, FocusRestoreEntry[]>();

function getDefaultDocument(): Document | null {
  return typeof document === "undefined" ? null : document;
}

function getFocusRestoreStack(ownerDocument: Document): FocusRestoreEntry[] {
  let stack = focusRestoreStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    focusRestoreStacks.set(ownerDocument, stack);
  }
  return stack;
}

function removeEntry(entry: FocusRestoreEntry): void {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const index = stack.lastIndexOf(entry);
  if (index >= 0) stack.splice(index, 1);
}

function resolveOptions(options: UseFocusRestoreOptions): Required<UseFocusRestoreOptions> {
  return {
    enabled: options.enabled ?? true,
    restoreOnUnmount: options.restoreOnUnmount ?? true,
    preventScroll: options.preventScroll ?? false,
    fallback: options.fallback ?? null,
  };
}

function releaseEntry(
  entry: FocusRestoreEntry,
  shouldRestore: boolean,
  options: Required<UseFocusRestoreOptions>,
): boolean {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const isTopEntry = stack.at(-1) === entry;
  removeEntry(entry);

  if (!shouldRestore || !options.enabled || !isTopEntry) return false;

  return (
    restoreFocus(entry.target, { preventScroll: options.preventScroll }) ||
    restoreFocus(options.fallback, { preventScroll: options.preventScroll })
  );
}

export function useFocusRestore(options: UseFocusRestoreOptions = {}): UseFocusRestoreReturn {
  const resolvedOptions = resolveOptions(options);
  const optionsRef = useRef(resolvedOptions);
  const entryRef = useRef<FocusRestoreEntry | null>(null);
  const [target, setTarget] = useState<HTMLElement | null>(null);

  // Stable-ref escape hatch: optionsRef is read ONLY inside capture/restore
  // event-driven callbacks and unmount cleanup (never during render), so
  // mid-render writes are safe under concurrent rendering. See AGENTS.md
  // react-useref rules.
  optionsRef.current = resolvedOptions;

  const capture = useCallback((ownerDocument?: Document) => {
    const resolvedOptions = optionsRef.current;
    if (!resolvedOptions.enabled) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const doc = ownerDocument ?? resolvedOptions.fallback?.ownerDocument ?? getDefaultDocument();
    if (!doc) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const nextTarget = getRestorableFocusTarget(doc) ?? resolvedOptions.fallback;
    const entry = entryRef.current ?? { target: null, ownerDocument: doc };

    removeEntry(entry);
    entry.target = nextTarget;
    entry.ownerDocument = doc;
    entryRef.current = entry;
    getFocusRestoreStack(doc).push(entry);
    setTarget(nextTarget);

    return nextTarget;
  }, []);

  const restore = useCallback(() => {
    const resolvedOptions = optionsRef.current;
    const entry = entryRef.current;

    if (!entry) {
      return resolvedOptions.enabled
        ? restoreFocus(resolvedOptions.fallback, { preventScroll: resolvedOptions.preventScroll })
        : false;
    }

    entryRef.current = null;
    const restored = releaseEntry(entry, true, resolvedOptions);
    setTarget(null);
    return restored;
  }, []);

  useEffect(() => {
    if (resolvedOptions.enabled) return;

    const entry = entryRef.current;
    if (!entry) return;

    entryRef.current = null;
    removeEntry(entry);
    setTarget(null);
  }, [resolvedOptions.enabled]);

  useEffect(() => {
    return () => {
      const entry = entryRef.current;
      if (!entry) return;

      entryRef.current = null;
      releaseEntry(entry, optionsRef.current.restoreOnUnmount, optionsRef.current);
    };
  }, []);

  return { capture, restore, target };
}

"use client";

import { type RefObject, useEffect, useRef } from "react";
import { getOwnerView, isNode } from "../dom/element-guards.js";
import { restoreFocus as restoreFocusTarget } from "../dom/focus-restore.js";
import { getFocusableElements, getTabbableElements, isFocusable } from "../dom/focusable.js";
import { useFocusRestore } from "./use-focus-restore.js";

export interface UseFocusTrapOptions {
  initialFocus?: RefObject<HTMLElement | null>;
  restoreFocus?: boolean;
  enabled?: boolean;
}

interface TrapEntry {
  container: HTMLElement;
  ownerDocument: Document;
  initialFocus: RefObject<HTMLElement | null> | undefined;
  lastFocused: HTMLElement;
  handleKeyDown: (event: KeyboardEvent) => void;
  handleFocusIn: (event: FocusEvent) => void;
  observer: MutationObserver;
  suspended: boolean;
}

interface ActiveTrap {
  container: HTMLElement;
  restoreFocus: boolean;
  release: () => void;
}

// Per-document trap stacks: only the top (last) entry in each document captures focus.
// When a new trap activates, the previous top is suspended (listeners removed).
// When the top trap releases, the next-in-stack is re-armed (listeners re-attached).
const trapStacks = new WeakMap<Document, TrapEntry[]>();

function getTrapStack(ownerDocument: Document): TrapEntry[] {
  let stack = trapStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    trapStacks.set(ownerDocument, stack);
  }
  return stack;
}

function suspendEntry(entry: TrapEntry): void {
  if (entry.suspended) return;
  entry.ownerDocument.removeEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.removeEventListener("focusin", entry.handleFocusIn, true);
  entry.observer.disconnect();
  entry.suspended = true;
}

function resumeEntry(entry: TrapEntry): void {
  if (!entry.suspended) return;
  entry.ownerDocument.addEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.addEventListener("focusin", entry.handleFocusIn, true);
  entry.observer.observe(entry.container, {
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ["disabled", "hidden", "tabindex", "aria-hidden", "inert"],
  });
  entry.suspended = false;
  // Recapture focus into the resumed trap's container
  const target =
    entry.container.contains(entry.lastFocused) &&
    entry.lastFocused.isConnected &&
    isFocusable(entry.lastFocused)
      ? entry.lastFocused
      : pickInitialTarget(entry.container, entry.initialFocus);
  target.focus();
}

function pushTrap(entry: TrapEntry): void {
  const stack = getTrapStack(entry.ownerDocument);
  const prev = stack.at(-1);
  if (prev) suspendEntry(prev);
  stack.push(entry);
}

function removeTrap(entry: TrapEntry): void {
  const stack = getTrapStack(entry.ownerDocument);
  const index = stack.indexOf(entry);
  if (index < 0) return;
  const wasTop = index === stack.length - 1;
  stack.splice(index, 1);
  if (wasTop) {
    const newTop = stack.at(-1);
    if (newTop) resumeEntry(newTop);
  }
}

function pickInitialTarget(
  container: HTMLElement,
  initialFocus: RefObject<HTMLElement | null> | undefined,
): HTMLElement {
  const requested = initialFocus?.current;
  if (requested && container.contains(requested) && isFocusable(requested)) return requested;
  return getFocusableElements(container)[0] ?? container;
}

function isInsideContainer(
  container: HTMLElement,
  target: EventTarget | null,
): target is HTMLElement {
  const View = getOwnerView(container);
  return isNode(target, View) && container.contains(target);
}

// Effect-on-every-render is intentional: React does not re-fire effects when
// containerRef.current mutates while the ref object stays stable.
export function useFocusTrap(
  containerRef: RefObject<HTMLElement | null>,
  options: UseFocusTrapOptions = {},
): void {
  const { initialFocus, restoreFocus = true, enabled = true } = options;
  const activeTrapRef = useRef<ActiveTrap | null>(null);
  const trapEntryRef = useRef<TrapEntry | null>(null);
  // useFocusRestore manages the focus-restore stack so nested overlays
  // restore correctly. Restoration itself happens in this hook's release()
  // so listeners are detached BEFORE focus moves out of the container --
  // otherwise the document-level focusin recapture re-traps the restored
  // target. `restoreOnUnmount: false` prevents the stack hook from moving
  // focus during its own unmount cleanup.
  const { capture } = useFocusRestore({
    enabled: restoreFocus,
    restoreOnUnmount: false,
  });

  // No dependency array on purpose; see hook-level comment above.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    const nextContainer = enabled ? containerRef.current : null;
    if (
      activeTrapRef.current?.container === nextContainer &&
      activeTrapRef.current.restoreFocus === restoreFocus
    ) {
      return;
    }

    activeTrapRef.current?.release();
    activeTrapRef.current = null;

    if (!nextContainer) return;
    const container = nextContainer;
    const ownerDocument = container.ownerDocument;
    const restoreTarget = capture(ownerDocument);

    const hadTabIndex = container.hasAttribute("tabindex");
    const originalTabIndex = container.getAttribute("tabindex");
    if (!hadTabIndex) container.setAttribute("tabindex", "-1");

    // lastFocused is set after initial focus below
    let lastFocused: HTMLElement = container;

    const recapture = () => {
      const target =
        container.contains(lastFocused) && lastFocused.isConnected && isFocusable(lastFocused)
          ? lastFocused
          : pickInitialTarget(container, initialFocus);
      target.focus();
    };

    const handleFocusIn = (event: FocusEvent) => {
      const target = event.target;
      if (isInsideContainer(container, target)) {
        lastFocused = target;
        // Keep the stack entry in sync so resume() can use it
        if (trapEntryRef.current) trapEntryRef.current.lastFocused = target;
        return;
      }
      recapture();
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key !== "Tab") return;

      const focusableEls = getTabbableElements(container);
      if (focusableEls.length === 0) {
        event.preventDefault();
        if (ownerDocument.activeElement !== container) container.focus();
        return;
      }

      const first = focusableEls[0];
      const last = focusableEls[focusableEls.length - 1];
      const activeElement = ownerDocument.activeElement;

      if (!isInsideContainer(container, activeElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first)?.focus();
        return;
      }

      if (!focusableEls.includes(activeElement as HTMLElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first)?.focus();
        return;
      }

      if (event.shiftKey) {
        if (activeElement === first) {
          event.preventDefault();
          last?.focus();
        }
      } else {
        if (activeElement === last) {
          event.preventDefault();
          first?.focus();
        }
      }
    };

    const observer = new MutationObserver(() => {
      if (lastFocused.isConnected && container.contains(lastFocused) && isFocusable(lastFocused))
        return;
      recapture();
    });

    // Build the stack entry and push it BEFORE attaching listeners or
    // focusing. pushTrap suspends the previous top trap so its focusin
    // handler does not recapture focus away from this new trap.
    const entry: TrapEntry = {
      container,
      ownerDocument,
      initialFocus,
      lastFocused,
      handleKeyDown,
      handleFocusIn,
      observer,
      suspended: false,
    };
    trapEntryRef.current = entry;
    pushTrap(entry);

    // Attach listeners and focus now that the outer trap is suspended
    ownerDocument.addEventListener("keydown", handleKeyDown, true);
    ownerDocument.addEventListener("focusin", handleFocusIn, true);
    observer.observe(container, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ["disabled", "hidden", "tabindex", "aria-hidden", "inert"],
    });

    const initialTarget = pickInitialTarget(container, initialFocus);
    initialTarget.focus();
    lastFocused = container.contains(ownerDocument.activeElement)
      ? (ownerDocument.activeElement as HTMLElement)
      : initialTarget;
    entry.lastFocused = lastFocused;

    activeTrapRef.current = {
      container,
      restoreFocus,
      release: () => {
        // Detach own listeners BEFORE removing from the stack. removeTrap
        // calls resumeEntry on the outer trap which focuses into the outer
        // container — if our focusin listener is still attached, it would
        // see that focus escaped and recapture, fighting the outer trap.
        ownerDocument.removeEventListener("keydown", handleKeyDown, true);
        ownerDocument.removeEventListener("focusin", handleFocusIn, true);
        observer.disconnect();

        // Remove from stack. This re-arms the outer trap (if any) which
        // recaptures focus into its container.
        removeTrap(entry);
        trapEntryRef.current = null;

        if (!hadTabIndex) {
          container.removeAttribute("tabindex");
        } else if (originalTabIndex !== null) {
          container.setAttribute("tabindex", originalTabIndex);
        }

        // Only restore focus to pre-trap target if there is no outer trap
        // waiting. When an outer trap exists, resumeEntry() already moved
        // focus back into the outer container.
        if (restoreFocus && getTrapStack(ownerDocument).length === 0) {
          restoreFocusTarget(restoreTarget);
        }
      },
    };
  });

  useEffect(() => {
    return () => {
      const activeTrap = activeTrapRef.current;
      if (!activeTrap) return;
      activeTrapRef.current = null;
      activeTrap.release();
    };
  }, []);
}

"use client";

import { type RefObject, useEffect, useRef } from "react";

const lockCounts = new WeakMap<Element, number>();
const savedOverflow = new WeakMap<Element, string>();

export interface UseScrollLockOptions {
  target?: RefObject<HTMLElement | null>;
  enabled?: boolean;
}

function lockElement(el: HTMLElement): () => void {
  const count = lockCounts.get(el) ?? 0;

  if (count === 0) {
    savedOverflow.set(el, el.style.overflow);
    el.style.overflow = "hidden";
  }
  lockCounts.set(el, count + 1);

  return () => {
    const current = lockCounts.get(el) ?? 1;
    const next = current - 1;
    if (next <= 0) {
      lockCounts.delete(el);
      el.style.overflow = savedOverflow.get(el) ?? "";
      savedOverflow.delete(el);
    } else {
      lockCounts.set(el, next);
    }
  };
}

// Effect-on-every-render is intentional: React does not re-fire effects when
// target.current mutates while the ref object stays stable.
export function useScrollLock(options: UseScrollLockOptions = {}): void {
  const { target, enabled = true } = options;
  const lockedElementRef = useRef<HTMLElement | null>(null);
  const releaseRef = useRef<(() => void) | null>(null);

  // No dependency array on purpose; see hook-level comment above.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    const nextElement = enabled ? (target?.current ?? document.body) : null;
    if (lockedElementRef.current === nextElement) return;

    releaseRef.current?.();
    releaseRef.current = null;
    lockedElementRef.current = null;

    if (!nextElement) return;

    releaseRef.current = lockElement(nextElement);
    lockedElementRef.current = nextElement;
  });

  useEffect(() => {
    return () => {
      releaseRef.current?.();
      releaseRef.current = null;
      lockedElementRef.current = null;
    };
  }, []);
}
